{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT Id, Name FROM Product2 WHERE Id='01tWt000006hV8LIAU';\"",
  "description": "Find product by ID"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT COUNT(*) FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\"",
  "description": "Count OrderItems for the product"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT issueid__c, COUNT(*) AS cnt FROM \\\"case\\\" WHERE orderitemid__c IN (SELECT Id FROM (VALUES $(sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT '('||''''||Id||''''||')' FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\" | paste -sd ',' -)) AS t(Id)) AND createddate >= '2022-08-16' AND createddate <= '2023-01-16' GROUP BY issueid__c ORDER BY cnt DESC LIMIT 10;\"",
  "description": "Count cases by issue for product over past 5 months"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"\\dt\"",
  "description": "List tables in support database"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"\\d \\\"Case\\\"\"",
  "description": "Check case schema"
}

{
  "command": "ORDER_IDS=$(sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT ''''||Id||'''' FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\" | paste -sd ',' -)\npsql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT issueid__c, COUNT(*) AS cnt FROM \\\"Case\\\" WHERE orderitemid__c IN ($ORDER_IDS) AND createddate >= '2022-08-16' AND createddate <= '2023-01-16' GROUP BY issueid__c ORDER BY cnt DESC LIMIT 10;\"",
  "description": "Count cases by issue"
}

{
  "command": "ORDER_IDS=$(sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT ''''||Id||'''' FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\" | paste -sd ',' -)\npsql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT issueid__c, COUNT(*) AS cnt, MIN(createddate), MAX(createddate) FROM \\\"Case\\\" WHERE orderitemid__c IN ($ORDER_IDS) GROUP BY issueid__c ORDER BY cnt DESC LIMIT 10;\"",
  "description": "Count cases by issue any date"
}

{
  "command": "ORDER_IDS=$(sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT ''''||Id||'''' FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\" | paste -sd ',' -)\npsql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT id, issueid__c, createddate, subject FROM \\\"Case\\\" WHERE orderitemid__c IN ($ORDER_IDS) ORDER BY createddate;\"",
  "description": "List all cases for this product"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT Id, Name FROM Product2 WHERE Name LIKE '%Cirku%' OR Name LIKE '%AI %';\"",
  "description": "Find all AI products"
}

{
  "command": "ORDER_IDS=$(sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT ''''||Id||'''' FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\" | paste -sd ',' -)\npsql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT issueid__c, COUNT(*) AS cnt FROM \\\"Case\\\" WHERE orderitemid__c IN ($ORDER_IDS) AND createddate::timestamp >= '2022-08-16'::timestamp AND createddate::timestamp < '2023-01-16'::timestamp + interval '1 day' GROUP BY issueid__c ORDER BY cnt DESC;\"",
  "description": "Strict past 5 months query"
}

{
  "command": "ORDER_IDS=$(sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT ''''||Id||'''' FROM OrderItem WHERE Product2Id='01tWt000006hV8LIAU';\" | paste -sd ',' -)\npsql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT issueid__c, i.name, COUNT(*) AS cnt FROM \\\"Case\\\" c LEFT JOIN issue__c i ON c.issueid__c = i.id WHERE orderitemid__c IN ($ORDER_IDS) GROUP BY issueid__c, i.name ORDER BY cnt DESC;\"",
  "description": "Join with issue table for names"
}
